```javascript
function slugify(title) {
  // Convert to lowercase
  let lowerCaseTitle = title.toLowerCase();

  // Remove punctuation and replace spaces with hyphens
  let cleanedTitle = lowerCaseTitle.replace(/[^\w\s-]/g, '').replace(/\s+/g, '-');

  // Trim leading/trailing hyphens
  let slug = cleanedTitle.trim('-');

  return slug;
}

// Example usage:
console.log(slugify("Hello World!")); // Output: "hello-world"
console.log(slugify("JavaScript Programming")); // Output: "javascript-programming"
console.log(slugify("API Documentation - Version 1.0")); // Output: "api-documentation-version-1-0"
```

