```python
import csv

def sum_amount(path):
    total = 0
    with open(path, mode='r', newline='') as file:
        reader = csv.DictReader(file)
        for row in reader:
            if 'amount' in row:
                try:
                    total += float(row['amount'])
                except ValueError:
                    print(f"Skipping invalid amount: {row['amount']}")
    return total
```

